#include <iostream>
using namespace std;

int main() {
    short  s  = 30000;
    int    i  = 2'000'000;     // digit separator (C++14)
    long long ll = 9'000'000'000LL;
    unsigned int u = 4'000'000'000u;

    cout << s  << endl;
    cout << i  << endl;
    cout << ll << endl;
    cout << u  << endl;

    cout << "sizeof int: "       << sizeof(int)       << " bytes" << endl;
    cout << "sizeof long long: " << sizeof(long long) << " bytes" << endl;

    return 0;
}

#include <iostream>
#include <iomanip>
using namespace std;

int main() {
    float  f = 1.23456789f;   // f suffix required for float
    double d = 1.23456789;

    cout << setprecision(9);
    cout << f << endl;  // loses precision
    cout << d << endl;  // full precision

    // The famous floating-point trap:
    cout << (0.1 + 0.2) << endl;
    cout << boolalpha << (0.1 + 0.2 == 0.3) << endl;

    return 0;
}

#include <iostream>
using namespace std;

int main() {
    char c = 'A';
    cout << c << endl;            // A
    cout << (int)c << endl;       // 65
    cout << (char)(c + 1) << endl; // B

    bool flag = true;
    cout << flag << endl;           // 1
    cout << boolalpha << flag << endl; // true

    // Loop through part of the alphabet:
    for (char ch = 'A'; ch <= 'E'; ch++) {
        cout << ch << " ";
    }
    cout << endl;

    return 0;
}

#include <iostream>
using namespace std;

int main() {
    int i = 42;
    double d = i;           // implicit widening — safe
    cout << d << endl;       // 42.0

    double pi = 3.99;
    int truncated = static_cast<int>(pi);  // drops decimal (no rounding!)
    cout << truncated << endl;             // 3

    // Integer division problem and fix:
    int a = 7, b = 2;
    cout << a / b << endl;                   // 3 (integer!)
    cout << static_cast<double>(a) / b << endl; // 3.5

    return 0;
}

#include <iostream>
#include <limits>
using namespace std;

int main() {
    cout << "int max: "       << numeric_limits<int>::max()    << endl;
    cout << "int min: "       << numeric_limits<int>::min()    << endl;
    cout << "double max: "    << numeric_limits<double>::max() << endl;
    cout << "double epsilon: "<< numeric_limits<double>::epsilon() << endl;

    // Overflow: undefined behaviour!
    int overflow = numeric_limits<int>::max();
    overflow++;  // wraps around on most platforms
    cout << "Overflowed: " << overflow << endl;

    return 0;
}

#include <iostream>
using namespace std;

int main() {
    int a = 0b1010;  // 10 in binary
    int b = 0b1100;  // 12 in binary

    cout << (a & b)  << endl;  // AND:  1000 = 8
    cout << (a | b)  << endl;  // OR:   1110 = 14
    cout << (a ^ b)  << endl;  // XOR:  0110 = 6
    cout << (1 << 4) << endl;  // left shift: 2^4 = 16
    cout << (16 >> 2) << endl; // right shift: 16/4 = 4

    // Check if a bit is set (common in games/flags):
    int flags = 0b0101;  // bits 0 and 2 are set
    cout << boolalpha << ((flags & (1 << 2)) != 0) << endl;  // bit 2 set?

    return 0;
}
